async function a(r=1){const o=`${window.APP_CONFIG?.baseUrl||"/"}api/regions?country_id=${r}`;try{const s=await(await fetch(o)).json();return s.success?s.data.map(t=>({id:t.id,name:t.region})):[]}catch(n){return console.error("Fetch Regions Error:",n),[]}}async function c(){const e=`${window.APP_CONFIG?.baseUrl||"/"}api/countries`,n=await(await fetch(e)).json();return n.success?n.data.map(s=>({id:s.id,name:s.country,code:s.country_code})):[]}export{a,c as f};
